from pathlib import Path
from report_link_utils import markdown_link
ROOT=Path(__file__).resolve().parents[1]; OUT=ROOT/'docs/planning/next-actions.md'; STATUS=ROOT/'docs/reports/project-status-generated.md'; GAP=ROOT/'docs/reports/research-gap-report.md'
TASKS=[
{'id':'STRATEGIC-001','priority':'high','title':'Prove the W2 S_core dynamics history and revision package','why':'W0 and W1 are complete. The next dependencies are deterministic and finite-support probabilistic bisimulation, history and path reflection, nonmonotonic revision, and operational self-modification. These must preserve rule identity, rule version, admissibility, weights, provenance, and exact before/after effects rather than labels alone.','affected':['docs/research/s-core-construction-obstruction-ledger-v1.0.md','theory/evaluation/s-core-construction-obstruction-ledger.json','docs/research/faithful-representation-specification-v1.0.md','docs/research/independent-reasoning-definition-v1.0.md'],'outcome':'A versioned proof-or-obstruction package resolving LEM-SC-010, LEM-SC-011, LEM-SC-013, LEM-SC-015, and LEM-SC-016, with OBS-SC-004 and OBS-SC-005 executed as dependencies close.','risk':'high','branch':'research/prove-s-core-w2-dynamics-history','pr':'Prove S_core W2 dynamics history and revision'},
{'id':'STRATEGIC-002','priority':'high','title':'Prove the W3 global witness obligations','why':'Per-axis target structures do not establish faithfulness until target-only recovery, semantic agreement, cross-axis coherence, machinery accounting, global uniformity, composition, and witness assembly are proved together.','affected':['docs/research/s-core-construction-obstruction-ledger-v1.0.md','theory/evaluation/s-core-construction-obstruction-ledger.json','docs/research/faithful-representation-specification-v1.0.md','theory/evaluation/thm-target-001.json'],'outcome':'Accepted construction lemmas or quantified obstructions for LEM-SC-017 through LEM-SC-024.','risk':'high','branch':'research/prove-s-core-w3-global-witness','pr':'Prove S_core W3 global witness obligations'},
{'id':'STRATEGIC-003','priority':'high','title':'Execute the remaining obstruction and negative-control program','why':'Two direct-axis impossibility hypotheses are refuted and one source boundary is established, but hidden-interpreter, dynamics, history, uniformity, composition, fixed-interface, and formal negative-control obligations remain open.','affected':['docs/research/s-core-construction-obstruction-ledger-v1.0.md','theory/evaluation/s-core-construction-obstruction-ledger.json','docs/methodology/negative-control-suite-v1.0.md','theory/falsification'],'outcome':'Accepted obstruction, refutation, scope-boundary, or unresolved records for every remaining OBS-SC obligation, including NC-01 through NC-10.','risk':'high','branch':'research/execute-s-core-obstructions','pr':'Execute remaining S_core obstruction program'},
{'id':'STRATEGIC-004','priority':'high','title':'Assemble the finite-core theorem or strongest obstruction','why':'Only after all registered dependencies are resolved may ASM-SC-001 through ASM-SC-003 derive the common schema, arbitrary-episode witness, and strongest justified theorem-or-obstruction outcome.','affected':['docs/research/s-core-construction-obstruction-ledger-v1.0.md','theory/evaluation/s-core-construction-obstruction-ledger.json','theory/evaluation/thm-target-001.json','theory/evaluation/central-claim-registry.json'],'outcome':'A complete scoped theorem, formal countermodel, proper-subclass theorem, or explicit unresolved result with every remaining obligation named.','risk':'high','branch':'research/assemble-s-core-result','pr':'Assemble S_core theorem or obstruction'}]
def nav_links(): return [f"- README Command Center: {markdown_link(ROOT/'README.md',OUT)}",f"- Project Status: {markdown_link(STATUS,OUT)}",f"- Research Gaps: {markdown_link(GAP,OUT)}",f"- Next Actions: {markdown_link(OUT,OUT)}"]
def main()->int:
    ids=[x['id'] for x in TASKS]; assert len(ids)==len(set(ids))
    lines=['# Next Actions','','## Navigation','',*nav_links(),'','Generated by `python tools/generate_next_tasks.py` under the deduction-first strategic priority. THM-TARGET-001, FAITHFUL-REP-001, P8-ROLE-001, and SCORE-LEMMA-LEDGER-001 remain frozen. SCORE-W0-PROOF-001 and SCORE-W1-PROOF-001 establish 11 construction lemmas, one source boundary, and two refuted obstruction hypotheses; 23 obligations remain and W2 is active. Research gaps remain available but do not automatically enter the central queue.','','## Ranked Next Actions','']
    for t in TASKS:
        affected=[markdown_link(ROOT/p,OUT) for p in t['affected']]
        lines += [f"### {t['id']}: {t['title']}",'','- Source: deduction-first strategic priority',f"- Priority: {t['priority']}",f"- Why it matters: {t['why']}",'- Affected files:',*[f'  - {x}' for x in affected],f"- Expected outcome: {t['outcome']}",f"- Risk level: {t['risk']}",f"- Suggested branch name: `{t['branch']}`",f"- Suggested PR title: `{t['pr']}`",'']
    lines += ['## Maintainer Task Briefs','']
    for t in TASKS:
        lines += [f"### Task brief for {t['id']}",'','```markdown',f"Create branch `{t['branch']}`.",f"Scope: {t['title']}.",'Preserve THM-TARGET-001, FAITHFUL-REP-001, P8-ROLE-001, SCORE-LEMMA-LEDGER-001, SCORE-W0-PROOF-001, SCORE-W1-PROOF-001, all failures and unresolved obligations, and every nonclaim.','Do not mark a lemma proved without a versioned proof artifact and dependency audit. Do not claim a representation theorem, universality, necessity, minimality, proof-assistant verification, actual-process correspondence, or independent validation without registered evidence.','Validation commands:','- `make research-check`','- `make health-fast`',f"PR title: `{t['pr']}`",'```','']
    lines += ['## Navigation','',*nav_links()]
    OUT.write_text('\n'.join(lines)+'\n',encoding='utf-8'); print(f'{OUT.relative_to(ROOT)} tasks={len(TASKS)}'); return 0
if __name__=='__main__': raise SystemExit(main())
